 {"id":"bd-3bxhj.2.10","title":"task(opentui-import ingestion tests): E2E ingestion script with deterministic replay logging","description":"Objective: Implement an end-to-end ingestion script that runs full source analysis on curated fixtures and emits deterministic JSONL traces suitable for replay triage.\\n\\nAcceptance criteria:\\n1. Script runs all ingestion stages and validates manifest completeness.\\n2. Re-running with same seed/context yields byte-identical traces.\\n3. Failures include stage-specific diagnostics and reproduction commands.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:29:38.743395709Z","created_by":"ubuntu","updated_at":"2026-02-24T22:20:11.766528062Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["e2e","ingestion","opentui-import","test"],"dependencies":[{"issue_id":"bd-3bxhj.2.10","depends_on_id":"bd-3bxhj.1.7","type":"blocks","created_at":"2026-02-24T22:20:11.766461256Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.10","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:29:38.743395709Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.10","depends_on_id":"bd-3bxhj.2.9","type":"blocks","created_at":"2026-02-24T21:37:14.566609232Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.11","title":"task(opentui-import ingestion): Harden untrusted project analysis sandbox (FS/network/process/resource controls)","description":"Objective: Ensure all source analysis and optional dynamic probes run in constrained sandbox boundaries to prevent unsafe execution and resource abuse from untrusted repositories.\\n\\nAcceptance criteria:\\n1. Sandbox enforces explicit FS, network, process, and CPU/memory limits.\\n2. Policy is profile-configurable with safe defaults and audit logs.\\n3. Violations fail closed with clear diagnostics and reproduction metadata.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:27.825537422Z","created_by":"ubuntu","updated_at":"2026-02-25T03:12:09.646270182Z","closed_at":"2026-02-25T03:12:09.646250696Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","opentui-import","security"],"dependencies":[{"issue_id":"bd-3bxhj.2.11","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:27.825537422Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.11","depends_on_id":"bd-3bxhj.2.1","type":"blocks","created_at":"2026-02-24T21:40:36.421124152Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.12","title":"task(opentui-import ingestion): Implement secret detection and artifact redaction pipeline","description":"Objective: Detect and redact sensitive tokens/credentials in source-derived artifacts, logs, and manifests while preserving debugging utility.\\n\\nAcceptance criteria:\\n1. Secret scanners run on raw inputs and generated outputs.\\n2. Redaction is deterministic, reversible only via secure local mapping, and traceable.\\n3. Certification/replay artifacts never expose raw secrets.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:28.287338931Z","created_by":"ubuntu","updated_at":"2026-02-25T03:18:14.596931764Z","closed_at":"2026-02-25T03:18:14.596913279Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","opentui-import","provenance","security"],"dependencies":[{"issue_id":"bd-3bxhj.2.12","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:28.287338931Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.12","depends_on_id":"bd-3bxhj.2.11","type":"blocks","created_at":"2026-02-24T21:40:36.879591715Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
-{"id":"bd-3bxhj.2.13","title":"task(opentui-import ingestion tests): Unit tests for sandbox policy enforcement and redaction correctness","description":"Objective: Validate sandbox constraints, denial paths, resource caps, and redaction correctness/false-positive controls with deterministic test fixtures.\\n\\nAcceptance criteria:\\n1. Unit tests cover allow/deny matrix and boundary resource scenarios.\\n2. Redaction tests validate no secret leakage across manifest/log/artifact paths.\\n3. Structured logs include policy rule IDs and redaction token fingerprints (non-sensitive).","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:28.782010367Z","created_by":"ubuntu","updated_at":"2026-02-24T21:40:38.303094664Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","opentui-import","security","test","unit"],"dependencies":[{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.1.6","type":"blocks","created_at":"2026-02-24T21:40:37.365349303Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:28.782010367Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.2.11","type":"blocks","created_at":"2026-02-24T21:40:37.832931150Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.2.12","type":"blocks","created_at":"2026-02-24T21:40:38.303053096Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
+{"id":"bd-3bxhj.2.13","title":"task(opentui-import ingestion tests): Unit tests for sandbox policy enforcement and redaction correctness","description":"Objective: Validate sandbox constraints, denial paths, resource caps, and redaction correctness/false-positive controls with deterministic test fixtures.\\n\\nAcceptance criteria:\\n1. Unit tests cover allow/deny matrix and boundary resource scenarios.\\n2. Redaction tests validate no secret leakage across manifest/log/artifact paths.\\n3. Structured logs include policy rule IDs and redaction token fingerprints (non-sensitive).","status":"in_progress","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:28.782010367Z","created_by":"ubuntu","updated_at":"2026-02-25T03:18:53.866024047Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","opentui-import","security","test","unit"],"dependencies":[{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.1.6","type":"blocks","created_at":"2026-02-24T21:40:37.365349303Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:28.782010367Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.2.11","type":"blocks","created_at":"2026-02-24T21:40:37.832931150Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.13","depends_on_id":"bd-3bxhj.2.12","type":"blocks","created_at":"2026-02-24T21:40:38.303053096Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.14","title":"task(opentui-import ingestion tests): E2E adversarial-ingestion script with security audit logging","description":"Objective: Build end-to-end adversarial ingestion suite (malicious scripts, path traversal attempts, oversized payloads, secret leakage probes) with deterministic security audit traces.\\n\\nAcceptance criteria:\\n1. Script verifies fail-closed behavior under hostile fixture corpus.\\n2. Security audit logs include policy decisions, blocked operations, and replay IDs.\\n3. CI gate fails on sandbox bypass or unredacted-secret detection.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:29.275155153Z","created_by":"ubuntu","updated_at":"2026-02-24T21:40:39.697650784Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["e2e","ingestion","opentui-import","security","test"],"dependencies":[{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.1.7","type":"blocks","created_at":"2026-02-24T21:40:38.769848720Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:29.275155153Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.2.10","type":"blocks","created_at":"2026-02-24T21:40:39.226658508Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.2.13","type":"blocks","created_at":"2026-02-24T21:40:39.697602724Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.2","title":"task(opentui-import ingestion): Resolve JS/TS toolchain context (package manager, tsconfig, bundler)","description":"Objective: Resolve runtime/build context needed to correctly interpret source semantics, including module resolution and JSX transform assumptions.\\n\\nAcceptance criteria:\\n1. Detect npm/pnpm/yarn lockfile context and workspace boundaries.\\n2. Parse tsconfig, path aliases, JSX mode, and strictness flags.\\n3. Detect bundler/runtime assumptions relevant for dynamic imports and env variables.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-24T21:29:22.871814964Z","created_by":"ubuntu","updated_at":"2026-02-25T02:34:16.879788448Z","closed_at":"2026-02-25T02:34:16.879769393Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","opentui-import","toolchain"],"dependencies":[{"issue_id":"bd-3bxhj.2.2","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:29:22.871814964Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.2","depends_on_id":"bd-3bxhj.2.1","type":"blocks","created_at":"2026-02-24T21:37:06.242723650Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.3","title":"task(opentui-import ingestion): Build module graph and migration entrypoint detector","description":"Objective: Construct complete project module graph and identify migration entrypoints for OpenTUI app roots and critical feature surfaces.\\n\\nAcceptance criteria:\\n1. Static graph includes import/export edges and dynamic import hints.\\n2. Entrypoint detector supports monorepo sub-app layouts.\\n3. Ambiguous roots generate deterministic ranked candidates with rationale.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:29:23.465702590Z","created_by":"ubuntu","updated_at":"2026-02-24T21:37:07.166960004Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","module-graph","opentui-import"],"dependencies":[{"issue_id":"bd-3bxhj.2.3","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:29:23.465702590Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.3","depends_on_id":"bd-3bxhj.2.1","type":"blocks","created_at":"2026-02-24T21:37:06.701142382Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.3","depends_on_id":"bd-3bxhj.2.2","type":"blocks","created_at":"2026-02-24T21:37:07.166879193Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}

@@ -32,6 +32,9 @@ native-backend = ["dep:ftui-tty"]
 # Enable persistent data structures (HAMT) for O(1) snapshot-based undo/redo.
 # Re-exports `im` crate types (HashMap, Vector, OrdMap) through `ftui_runtime::undo::persistent`.
 hamt = ["dep:im"]
+# Enable event trace recording and replay for deterministic debugging.
+# Adds JSONL + gzip serialization of input events with nanosecond timestamps.
+event-trace = ["dep:serde", "dep:serde_json", "dep:flate2"]
 # Enable OpenTelemetry telemetry export via OTLP.
 # When enabled, spans can be exported to an OTLP collector.
 # Zero overhead when feature is off; minimal overhead when on but disabled via env.
@@ -69,6 +72,7 @@ serde = { version = "1.0.227", features = ["derive"], optional = true }
 serde_json = { version = "1.0.145", optional = true }
 base64 = { version = "0.22", optional = true }
 im = { version = "15.1", optional = true }
+flate2 = { version = "1.1", optional = true }

 [dev-dependencies]
 ftui-core = { path = "../ftui-core", version = "0.2.1", features = ["test-helpers"] }
